"""MCP-specific configuration: docs base URL and cache directory."""

import os
from pathlib import Path

from .guides import DOCS_BASE_URL as _DEFAULT_BASE_URL


def get_docs_base_url() -> str:
    """Return the base URL for docs (env override or default from guides)."""
    return os.environ.get("GREENNODE_DOCS_BASE_URL", os.environ.get("MCP_DOCS_BASE_URL", _DEFAULT_BASE_URL))


def get_cache_dir() -> Path:
    """Return the directory for caching fetched guide markdown (env override or XDG/default)."""
    if "GREENNODE_MCP_CACHE_DIR" in os.environ:
        return Path(os.environ["GREENNODE_MCP_CACHE_DIR"])
    if "XDG_CACHE_HOME" in os.environ:
        return Path(os.environ["XDG_CACHE_HOME"]) / "greennode-agentbase" / "guides"
    return Path.home() / ".cache" / "greennode-agentbase" / "guides"
